# - Detailed error reporting

param(
    [string]$ConfigFile = "deploy.config.json",
    [switch]$Build = $false,
    [switch]$DryRun = $false,
    [switch]$SkipHealthCheck = $false,
    [switch]$Verbose = $false
)

# ============================================================================
# CONFIGURATION & LOGGING
# ============================================================================

$ErrorActionPreference = "Stop"
$ScriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$Timestamp = Get-Date -Format "yyyyMMdd_HHmmss"
$LogFile = "$ScriptDir\deploy_$Timestamp.log"

function Write-Log {
    param([string]$Message, [string]$Level = "INFO")
    $LogMessage = "[$Timestamp] [$Level] $Message"
    Write-Host $LogMessage -ForegroundColor $(
        switch($Level) {
            "ERROR" { "Red" }
            "WARN" { "Yellow" }
            "SUCCESS" { "Green" }
            default { "White" }
        }
    )
    Add-Content -Path $LogFile -Value $LogMessage
}

function Exit-WithError {
    param([string]$Message)
    Write-Log "DEPLOYMENT FAILED: $Message" "ERROR"
    exit 1
}

Write-Log "========================================" "INFO"
Write-Log "TUC RMS Deployment Started" "INFO"
Write-Log "========================================" "INFO"

# ============================================================================
# STEP 1: LOAD & VALIDATE CONFIGURATION
# ============================================================================

Write-Log "Step 1: Loading configuration from $ConfigFile..." "INFO"

if (-not (Test-Path $ConfigFile)) {
    Exit-WithError "Configuration file not found: $ConfigFile"
}

try {
    $Config = Get-Content $ConfigFile | ConvertFrom-Json
    Write-Log "Configuration loaded successfully" "SUCCESS"
} catch {
    Exit-WithError "Invalid JSON in $ConfigFile : $_"
}

# Validate required config fields
$RequiredFields = @("projectName", "remoteHost", "deployPath", "buildTool", "outputDir")
foreach ($field in $RequiredFields) {
    if (-not $Config.$field) {
        Exit-WithError "Missing required config field: $field"
    }
}

Write-Log "Project: $($Config.projectName)" "INFO"
Write-Log "Remote: $($Config.remoteHost):$($Config.deployPath)" "INFO"
Write-Log "Build Tool: $($Config.buildTool)" "INFO"

# ============================================================================
# STEP 2: PRE-FLIGHT CHECKS
# ============================================================================

Write-Log "Step 2: Running pre-flight checks..." "INFO"

# Check if we're in the right directory (look for frontend/)
if (-not (Test-Path "frontend")) {
    Exit-WithError "frontend/ directory not found. Run this script from the project root."
}

Write-Log "✓ Project structure verified" "SUCCESS"

# Check if package.json exists in frontend
if (-not (Test-Path "frontend/package.json")) {
    Exit-WithError "frontend/package.json not found"
}

Write-Log "✓ package.json found" "SUCCESS"

# Check if .env.template exists and suggest creating .env.local
if (Test-Path "frontend/.env.template") {
    if (-not (Test-Path "frontend/.env.local")) {
        Write-Log "WARN: frontend/.env.local not found. Copy from .env.template if deploying." "WARN"
    } else {
        Write-Log "✓ frontend/.env.local exists" "SUCCESS"
    }
}

# ============================================================================
# STEP 3: BUILD FRONTEND (OPTIONAL)
# ============================================================================

if ($Build) {
    Write-Log "Step 3: Building frontend..." "INFO"
    
    Push-Location "frontend"
    
    Write-Log "Installing dependencies (if needed)..." "INFO"
    if ($Config.buildTool -eq "pnpm") {
        if (-not (Get-Command pnpm -ErrorAction SilentlyContinue)) {
            Exit-WithError "pnpm not installed. Install via: npm install -g pnpm"
        }
        & pnpm install --frozen-lockfile | Out-Null
    } else {
        & npm install --legacy-peer-deps | Out-Null
    }
    
    Write-Log "Building production bundle..." "INFO"
    if ($Config.buildTool -eq "pnpm") {
        & pnpm run build
    } else {
        & npm run build
    }
    
    if ($LASTEXITCODE -ne 0) {
        Pop-Location
        Exit-WithError "Build failed. Check output above."
    }
    
    Write-Log "✓ Build completed successfully" "SUCCESS"
    Pop-Location
} else {
    Write-Log "Step 3: Skipped (use -Build flag to rebuild)" "INFO"
}

# ============================================================================
# STEP 4: VERIFY BUILD OUTPUT
# ============================================================================

Write-Log "Step 4: Verifying build output..." "INFO"

$OutputPath = "frontend/$($Config.outputDir)"
if (-not (Test-Path $OutputPath)) {
    Exit-WithError "Output directory not found: $OutputPath. Run with -Build flag."
}

$FileCount = (Get-ChildItem $OutputPath -Recurse | Measure-Object).Count
Write-Log "Files in dist/: $FileCount" "INFO"

if ($FileCount -eq 0) {
    Exit-WithError "Output directory is empty. Build may have failed."
}

if (-not (Test-Path "$OutputPath/index.html")) {
    Exit-WithError "index.html not found in output directory"
}

Write-Log "✓ Build output verified ($FileCount files)" "SUCCESS"

# ============================================================================
# STEP 5: PREPARE FOR DEPLOYMENT
# ============================================================================

Write-Log "Step 5: Preparing for deployment..." "INFO"

$FrontendSourcePath = "frontend/$($Config.outputDir)"
$BackendSourcePath = "backend"

Write-Log "Frontend source: $FrontendSourcePath" "INFO"
Write-Log "Backend source: $BackendSourcePath" "INFO"

# ============================================================================
# STEP 6: DEPLOY TO REMOTE (SSH/SCP)
# ============================================================================

Write-Log "Step 6: Deploying to remote server..." "INFO"

if ($DryRun) {
    Write-Log "DRY RUN MODE - No changes will be made" "WARN"
}

# Parse SSH details
$SSHHost = $Config.remoteHost.Split("@")[1]
$SSHUser = $Config.remoteHost.Split("@")[0]

Write-Log "SSH User: $SSHUser" "INFO"
Write-Log "SSH Host: $SSHHost" "INFO"

# Test SSH connectivity
Write-Log "Testing SSH connectivity..." "INFO"
try {
    ssh "$($Config.remoteHost)" "echo 'SSH connectivity OK'" 2>&1 | Out-Null
    Write-Log "✓ SSH connection successful" "SUCCESS"
} catch {
    Exit-WithError "SSH connection failed to $($Config.remoteHost). Check SSH key and host availability."
}

# Create remote directory structure
Write-Log "Creating remote directory: $($Config.deployPath)..." "INFO"

if (-not $DryRun) {
    try {
        ssh "$($Config.remoteHost)" "mkdir -p $($Config.deployPath)" 2>&1 | Out-Null
        Write-Log "✓ Remote directory created/verified" "SUCCESS"
    } catch {
        Exit-WithError "Failed to create remote directory: $_"
    }
} else {
    Write-Log "[DRY RUN] Would create: $($Config.deployPath)" "INFO"
}

# Backup existing deployment (optional)
Write-Log "Creating backup of existing deployment..." "INFO"
if (-not $DryRun) {
    ssh "$($Config.remoteHost)" "cd $($Config.deployPath) && [ -d './index.html' ] && mv index.html index.html.backup-$Timestamp || true" 2>&1 | Out-Null
}

# Copy frontend dist/ to remote
Write-Log "Uploading frontend files via SCP..." "INFO"

if (-not $DryRun) {
    try {
        # Use bash for SCP to ensure cross-platform compatibility
        bash -c "scp -r '$FrontendSourcePath/*' '$($Config.remoteHost):$($Config.deployPath)/'"
        if ($LASTEXITCODE -ne 0) {
            Exit-WithError "SCP upload failed. Check permissions and path."
        }
        Write-Log "✓ Frontend files uploaded" "SUCCESS"
    } catch {
        Exit-WithError "SCP error: $_"
    }
} else {
    Write-Log "[DRY RUN] Would upload: $FrontendSourcePath/* to $($Config.remoteHost):$($Config.deployPath)/" "INFO"
}

# Copy .htaccess to remote (CRITICAL: use SSH heredoc to avoid PowerShell BOM)
Write-Log "Creating .htaccess on remote server..." "INFO"

if (-not $DryRun) {
    $HtaccessContent = @"
<IfModule mod_rewrite.c>
  RewriteEngine On
  RewriteBase $($Config.htaccessRewriteBase)
  RewriteCond %{REQUEST_FILENAME} -f
  RewriteRule ^ - [L]
  RewriteCond %{REQUEST_FILENAME} -d
  RewriteRule ^ - [L]
  RewriteRule ^ index.html [QSA,L]
</IfModule>
<IfModule mod_deflate.c>
  AddOutputFilterByType DEFLATE text/html text/plain text/xml text/css text/javascript application/javascript application/json
</IfModule>
<FilesMatch "\.js$|\.css$|\.woff|\.woff2|\.ttf|\.svg|\.eot">
  Header set Cache-Control "max-age=31536000, public"
</FilesMatch>
<FilesMatch "\.html$">
  Header set Cache-Control "max-age=3600, must-revalidate"
</FilesMatch>
Header set X-Content-Type-Options "nosniff"
Header set X-Frame-Options "DENY"
Header set X-XSS-Protection "1; mode=block"
Header set Strict-Transport-Security "max-age=31536000; includeSubDomains"
"@

    try {
        ssh "$($Config.remoteHost)" "cat > $($Config.deployPath)/.htaccess << 'HTACCESS_EOF'
$HtaccessContent
HTACCESS_EOF"
        Write-Log "✓ .htaccess created successfully" "SUCCESS"
    } catch {
        Exit-WithError ".htaccess creation failed: $_"
    }
} else {
    Write-Log "[DRY RUN] Would create .htaccess at: $($Config.deployPath)/.htaccess" "INFO"
}

# Set permissions
Write-Log "Setting permissions on remote files..." "INFO"
if (-not $DryRun) {
    ssh "$($Config.remoteHost)" "chmod -R 755 $($Config.deployPath)" 2>&1 | Out-Null
    Write-Log "✓ Permissions set (755)" "SUCCESS"
}

# ============================================================================
# STEP 7: HEALTH CHECKS
# ============================================================================

if (-not $SkipHealthCheck) {
    Write-Log "Step 7: Running health checks..." "INFO"
    
    # Check if files exist on remote
    Write-Log "Checking if index.html exists on remote..." "INFO"
    try {
        ssh "$($Config.remoteHost)" "test -f $($Config.deployPath)/index.html"
        if ($LASTEXITCODE -eq 0) {
            Write-Log "✓ index.html verified on remote" "SUCCESS"
        } else {
            Exit-WithError "index.html not found on remote server"
        }
    } catch {
        Exit-WithError "File verification failed: $_"
    }
    
    # Check .htaccess syntax via Apache
    Write-Log "Validating .htaccess syntax..." "INFO"
    try {
        ssh "$($Config.remoteHost)" "apache2ctl configtest 2>&1 | grep -i 'Syntax OK'"
        if ($LASTEXITCODE -eq 0) {
            Write-Log "✓ Apache configuration valid" "SUCCESS"
        } else {
            Write-Log "WARNING: Apache config test inconclusive. Check manually." "WARN"
        }
    } catch {
        Write-Log "Apache configtest skipped (may not be running)" "WARN"
    }
    
    # HTTP health check (wait for server to settle)
    Write-Log "Waiting 5 seconds for server to settle..." "INFO"
    Start-Sleep -Seconds 5
    
    Write-Log "Testing frontend health check endpoint..." "INFO"
    try {
        $HealthResponse = Invoke-WebRequest -Uri $Config.healthCheckUrl -UseBasicParsing -TimeoutSec 10
        if ($HealthResponse.StatusCode -eq 200) {
            Write-Log "✓ Frontend is responding (HTTP 200)" "SUCCESS"
        } else {
            Write-Log "WARNING: Unexpected HTTP status: $($HealthResponse.StatusCode)" "WARN"
        }
    } catch {
        Write-Log "WARNING: Could not reach frontend ($($Config.healthCheckUrl)). May require public DNS/IP." "WARN"
    }
    
} else {
    Write-Log "Step 7: Health checks skipped (use -SkipHealthCheck to disable)" "INFO"
}

# ============================================================================
# DEPLOYMENT COMPLETE
# ============================================================================

Write-Log "========================================" "SUCCESS"
Write-Log "✓ DEPLOYMENT COMPLETED SUCCESSFULLY" "SUCCESS"
Write-Log "========================================" "SUCCESS"
Write-Log "Frontend deployed to: $($Config.deployPath)" "SUCCESS"
Write-Log "Access at: $($Config.healthCheckUrl)" "SUCCESS"
Write-Log "Log saved to: $LogFile" "SUCCESS"
_deployStart = Get-Date
