# Timestamped logging helper (injected by standardisation pass — May 2026)
# TUC Results Management System — Deployment Script (Windows PowerShell)
# Usage: .\deploy.ps1 -ConfigFile deploy.config.json -Build -DryRun
# 
# Features:
# - Validates configuration and environment
# - Builds frontend (optional)
# - Verifies build output
# - Deploys to remote server via SSH/SCP
# - Creates .htaccess (avoiding PowerShell UTF-8 BOM issue)
# - Runs health checks
# - Detailed error reporting

param(
    [string]$ConfigFile = "deploy.config.json",
    [switch]$Build = $false,
    [switch]$DryRun = $false,
    [switch]$SkipHealthCheck = $false,
    [switch]$Verbose = $false
)

# ============================================================================
# CONFIGURATION & LOGGING
# ============================================================================

$ErrorActionPreference = "Stop"
$ScriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$Timestamp = Get-Date -Format "yyyyMMdd_HHmmss"
$LogFile = "$ScriptDir\deploy_$Timestamp.log"

function Write-Log {
    param([string]$Message, [string]$Level = "INFO")
    $LogMessage = "[$Timestamp] [$Level] $Message"
    Write-Host $LogMessage -ForegroundColor $(
        switch($Level) {
            "ERROR" { "Red" }
            "WARN" { "Yellow" }
            "SUCCESS" { "Green" }
            default { "White" }
        }
    )
    Add-Content -Path $LogFile -Value $LogMessage
}

function Exit-WithError {
    param([string]$Message)
    Write-Log "DEPLOYMENT FAILED: $Message" "ERROR"
    exit 1
}

Write-Log "========================================" "INFO"
Write-Log "TUC RMS Deployment Started" "INFO"
Write-Log "========================================" "INFO"

# ============================================================================
# STEP 1: LOAD & VALIDATE CONFIGURATION
# ============================================================================

Write-Log "Step 1: Loading configuration from $ConfigFile..." "INFO"

if (-not (Test-Path $ConfigFile)) {
    Exit-WithError "Configuration file not found: $ConfigFile"
}

try {
    $Config = Get-Content $ConfigFile | ConvertFrom-Json
    Write-Log "Configuration loaded successfully" "SUCCESS"
} catch {
    Exit-WithError "Invalid JSON in $ConfigFile : $_"
}

# Validate required config fields
$RequiredFields = @("projectName", "remoteHost", "deployPath", "buildTool", "outputDir")
foreach ($field in $RequiredFields) {
    if (-not $Config.$field) {
        Exit-WithError "Missing required config field: $field"
    }
}

Write-Log "Project: $($Config.projectName)" "INFO"
Write-Log "Remote: $($Config.remoteHost):$($Config.deployPath)" "INFO"
